patch:
diff --git a/llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp b/llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp
index 81088c9a8139..b859d40a3f97 100644
--- a/llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp
@@ -983,7 +983,11 @@ static Value *tryToFoldLiveIns(const VPRecipeBase &R, unsigned Opcode,
   case Instruction::InsertElement:
     return Folder.FoldInsertElement(Ops[0], Ops[1], Ops[2]);
   case Instruction::ExtractElement:
+  if (Ops[0] && Ops[0]->getType()->isVectorTy())
+  if (Ops[0] && Ops[0]->getType()->isVectorTy())
     return Folder.FoldExtractElement(Ops[0], Ops[1]);
+  return nullptr;
+  return nullptr;
   }
   return nullptr;
 }

